def parse_user_input(prompt: str) -> list:
    """Parse comma-separated user input into a list."""
    raw = input(prompt).strip()
    if not raw:
        return []
    return [item.strip() for item in raw.split(",")]


def interactive_mode(client: RedisLuaClient):
    """Run the client in interactive mode."""
    print("\n" + "=" * 60)
    print("  Redis Lua Script Executor - Interactive Mode")
    print("=" * 60)

    while True:
        print("\nOptions:")
        print("  1. Execute a custom Lua script")
        print("  2. Execute a built-in script template")
        print("  3. List built-in scripts")
        print("  4. Execute cached script (EVALSHA)")
        print("  5. Flush script cache")
        print("  6. Quick Redis command (GET/SET/DEL)")
        print("  7. Exit")
        print()

        choice = input("Select option [1-7]: ").strip()

        if choice == "1":
            print("\nEnter your Lua script (type 'END' on a new line to finish):")
            print("  Use KEYS[n] for key references and ARGV[n] for arguments.")
            lines = []
            while True:
                line = input()
                if line.strip().upper() == "END":
                    break
                lines.append(line)

            script = "\n".join(lines)

            if not script.strip():
                print("[WARN] Empty script, skipping.")
                continue

            keys = parse_user_input("Enter KEYS (comma-separated, or empty): ")
            args = parse_user_input("Enter ARGV (comma-separated, or empty): ")

            print(f"\n[INFO] Executing script with {len(keys)} keys and {len(args)} args...")
            result = client.execute_lua_script(script, keys, args)
            print(f"[RESULT] {result}")

        elif choice == "2":
            if not BUILTIN_SCRIPTS:
                print("[WARN] No built-in scripts available.")
                continue

            print("\nAvailable built-in scripts:")
            for idx, (name, info) in enumerate(BUILTIN_SCRIPTS.items(), 1):
                print(f"  {idx}. {name}: {info['description']}")
                print(f"     KEYS: {info['keys_hint']}")
                print(f"     ARGV: {info['args_hint']}")

            script_choice = input("\nEnter script name or number: ").strip()

            # Allow selection by number
            try:
                script_idx = int(script_choice) - 1
                script_name = list(BUILTIN_SCRIPTS.keys())[script_idx]
            except (ValueError, IndexError):
                script_name = script_choice

            if script_name not in BUILTIN_SCRIPTS:
                print(f"[ERROR] Unknown script: {script_name}")
                continue

            template = BUILTIN_SCRIPTS[script_name]
            print(f"\n[INFO] Running: {template['description']}")
            print(f"  Expected KEYS: {template['keys_hint']}")
            print(f"  Expected ARGV: {template['args_hint']}")

            keys = parse_user_input("Enter KEYS (comma-separated): ")
            args = parse_user_input("Enter ARGV (comma-separated): ")

            result = client.execute_lua_script(template["script"], keys, args)
            print(f"[RESULT] {result}")

        elif choice == "3":
            print("\n--- Built-in Lua Script Templates ---")
            for name, info in BUILTIN_SCRIPTS.items():
                print(f"\n  [{name}]")
                print(f"  Description: {info['description']}")
                print(f"  KEYS: {info['keys_hint']}")
                print(f"  ARGV: {info['args_hint']}")
                print(f"  Script:")
                for line in info['script'].strip().split('\n'):
                    print(f"    {line}")
            print()

        elif choice == "4":
            print("\nEnter your Lua script for cached execution (type 'END' to finish):")
            lines = []
            while True:
                line = input()
                if line.strip().upper() == "END":
                    break
                lines.append(line)

            script = "\n".join(lines)

            if not script.strip():
                print("[WARN] Empty script, skipping.")
                continue

            keys = parse_user_input("Enter KEYS (comma-separated, or empty): ")
            args = parse_user_input("Enter ARGV (comma-separated, or empty): ")

            print(f"\n[INFO] Executing cached script with {len(keys)} keys and {len(args)} args...")
            result = client.execute_cached_script(script, keys, args)
            print(f"[RESULT] {result}")

        elif choice == "5":
            client.flush_script_cache()

        elif choice == "6":
            cmd = input("Enter command (e.g., 'SET mykey myvalue', 'GET mykey', 'DEL mykey'): ").strip()
            parts = cmd.split()
            if not parts:
                continue
            try:
                op = parts[0].upper()
                if op == "SET" and len(parts) >= 3:
                    client.client.set(parts[1], " ".join(parts[2:]))
                    print("[OK] Value set.")
                elif op == "GET" and len(parts) >= 2:
                    val = client.client.get(parts[1])
                    print(f"[RESULT] {val}")
                elif op == "DEL" and len(parts) >= 2:
                    deleted = client.client.delete(*parts[1:])
                    print(f"[OK] Deleted {deleted} key(s).")
                elif op == "KEYS" and len(parts) >= 2:
                    keys = client.client.keys(parts[1])
                    print(f"[RESULT] {keys}")
                else:
                    print("[WARN] Supported: SET, GET, DEL, KEYS")
            except Exception as e:
                print(f"[ERROR] {e}")

        elif choice == "7":
            print("Goodbye!")
            break
        else:
            print("[WARN] Invalid option, please try again.")


def demo_mode(client: RedisLuaClient):
    """Run demonstration of built-in scripts."""
    print("\n" + "=" * 60)
    print("  Redis Lua Script Executor - Demo Mode")
    print("=" * 60)

    # Demo 1: Atomic increment with expiry
    print("\n--- Demo 1: Atomic Increment with Expiry ---")
    script = BUILTIN_SCRIPTS["atomic_increment_with_expiry"]["script"]
    for i in range(5):
        result = client.execute_lua_script(script, ["demo:counter"], ["60"])
        print(f"  Increment #{i + 1}: counter = {result}")

    # Demo 2: Get or Set
    print("\n--- Demo 2: Get or Set ---")
    script = BUILTIN_SCRIPTS["get_or_set"]["script"]
    result = client.execute_lua_script(script, ["demo:cached_value"], ["default_data", "300"])
    print(f"  First call (should set): {result}")
    result = client.execute_lua_script(script, ["demo:cached_value"], ["different_data", "300"])
    print(f"  Second call (should get existing): {result}")

    # Demo 3: Conditional update (CAS)
    print("\n--- Demo 3: Conditional Update (Compare-And-Swap) ---")
    client.client.set("demo:cas_key", "version1")
    script = BUILTIN_SCRIPTS["conditional_update"]["script"]
    result = client.execute_lua_script(script, ["demo:cas_key"], ["version1", "version2", "300"])
    print(f"  Update version1 -> version2 (should succeed): {result}")
    result = client.execute_lua_script(script, ["demo:cas_key"], ["version1", "version3", "300"])
    print(f"  Update version1 -> version3 (should fail, current is version2): {result}")

    # Demo 4: Custom Lua script
    print("\n--- Demo 4: Custom Lua Script (JSON-like aggregation) ---")
    client.client.hset("demo:user:1", mapping={"name": "Alice", "score": "100", "level": "5"})
    client.client.hset("demo:user:2", mapping={"name": "Bob", "score": "250", "level": "8"})

    custom_script = """
        local result = {}
        for i, key in ipairs(KEYS) do
            local name = redis.call('HGET', key, 'name')
            local score = redis.call('HGET', key, 'score')
            result[i] = name .. ':' .. score
        end
        return result
    """
    result = client.execute_lua_script(custom_script, ["demo:user:1", "demo:user:2"])
    print(f"  User scores: {result}")

    # Demo 5: Cached script execution
    print("\n--- Demo 5: Cached Script Execution (EVALSHA) ---")
    simple_script = "return redis.call('SET', KEYS[1], ARGV[1])"
    result = client.execute_cached_script(simple_script, ["demo:evalsha_key"], ["cached_value"])
    print(f"  Set via EVALSHA: {result}")
    val = client.client.get("demo:evalsha_key")
    print(f"  Verify GET: {val}")

    # Cleanup demo keys
    print("\n--- Cleaning up demo keys ---")
    demo_keys = client.client.keys("demo:*")
    if demo_keys:
        client.client.delete(*demo_keys)
        print(f"  Deleted {len(demo_keys)} demo keys.")

    print("\n[OK] Demo complete!")


def main():
    """Main entry point."""
    import argparse

    parser = argparse.ArgumentParser(description="Redis Lua Script Executor")
    parser.add_argument("--host", default="localhost", help="Redis host (default: localhost)")
    parser.add_argument("--port", type=int, default=6379, help="Redis port (default: 6379)")
    parser.add_argument("--db", type=int, default=0, help="Redis database (default: 0)")
    parser.add_argument("--password", default=None, help="Redis password")
    parser.add_argument("--mode", choices=["interactive", "demo"], default="interactive",
                        help="Run mode (default: interactive)")
    parser.add_argument("--script", type=str, default=None,
                        help="Execute a single Lua script and exit")
    parser.add_argument("--keys", type=str, default="",
                        help="Comma-separated keys for --script mode")
    parser.add_argument("--args", type=str, default="",
                        help="Comma-separated args for --script mode")

    parsed_args = parser.parse_args()

    client = RedisLuaClient(
        host=parsed_args.host,
        port=parsed_args.port,
        db=parsed_args.db,
        password=parsed_args.password
    )

    if parsed_args.script:
        # Single script execution mode
        keys = [k.strip() for k in parsed_args.keys.split(",") if k.strip()]
        args = [a.strip() for a in parsed_args.args.split(",") if a.strip()]

        # Support reading script from file
        if parsed_args.script.endswith(".lua"):
            try:
                with open(parsed_args.script, "r") as f:
                    script = f.read()
            except FileNotFoundError:
                print(f"[ERROR] File not found: {parsed_args.script}")
                sys.exit(1)
        else:
            script = parsed_args.script

        result = client.execute_lua_script(script, keys, args)
        print(json.dumps(result) if isinstance(result, (list, dict)) else result)

    elif parsed_args.mode == "demo":
        demo_mode(client)
    else:
        interactive_mode(client)


if __name__ == "__main__":
    main()